"use strict";parserFactory.register("mznovels.com",()=>new MznovelsParser);class MznovelsParser extends Parser{constructor(){super()}populateUIImpl(){document.getElementById("removeAuthorNotesRow").hidden=!1}async getChapterUrls(e,t){let r=this.extractPartialChapterList(e),a=this.getUrlsOfTocPages(e);return(await this.getChaptersFromAllTocPages(r,this.extractPartialChapterList,a,t)).reverse()}getUrlsOfTocPages(e){let t=[],r=e.querySelector(".pagination");if(r){let e=new URL(r.querySelector("a").href),a=this.maxTocPage(r);for(let r=2;r<=a;r++)e.searchParams.set("page",r),t.push(e.href)}return t}maxTocPage(e){let t=[...e.querySelectorAll("a")].map(e=>new URL(e?.href)?.searchParams?.get("page")).filter(e=>null!==e).map(e=>parseInt(e));return 0<t.length?Math.max(...t):0}extractPartialChapterList(e){let t=e.querySelector(".chapter-list");return util.hyperlinksToChapterList(t)}findContent(e){return e.querySelector(".chapter-content")}preprocessRawDom(e){let t=this.findContent(e);if(!this.userPreferences.removeAuthorNotes.value){let r=e.querySelector("div.author_note");if(r){util.removeChildElementsMatchingSelector(r,".author_note_avatar > img");for(let t of[...r.querySelectorAll(".note_content")])util.convertPreTagToPTags(e,t,"\n");t.appendChild(r)}}}extractTitleImpl(e){return e.querySelector(".novel-title")}extractAuthor(e){let t=e.querySelector(".novel-author a");return t?.textContent??super.extractAuthor(e)}findChapterTitle(e){return e.querySelector("h1")}findCoverImageUrl(e){return util.getFirstImgSrc(e,".novel-image-container")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll(".novel-summary")]}cleanInformationNode(e){return util.removeChildElementsMatchingSelector(e,"button"),e}}